"use strict";(self.webpackChunkusers_pomili_code_web_docs_site=self.webpackChunkusers_pomili_code_web_docs_site||[]).push([["9351"],{930(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"ml-roadmap","metadata":{"permalink":"/en/blog/ml-roadmap","editUrl":"https://github.com/pomili/docs-site/tree/main/blog/2026-05-22-ml-roadmap/index.mdx","source":"@site/blog/2026-05-22-ml-roadmap/index.mdx","title":"\u673A\u5668\u5B66\u4E60\u5B66\u4E60\u8DEF\u7EBF\uFF1A\u4ECE\u5165\u95E8\u5230\u5B9E\u8DF5","description":"\u4ECE\u6570\u5B66\u57FA\u7840\u5230\u5DE5\u7A0B\u843D\u5730\uFF0C\u5206\u4EAB\u4E00\u6761\u53EF\u6267\u884C\u7684\u673A\u5668\u5B66\u4E60\u5B66\u4E60\u8DEF\u7EBF\u3002","date":"2026-05-22T00:00:00.000Z","tags":[{"inline":false,"label":"\u673A\u5668\u5B66\u4E60","permalink":"/en/blog/tags/machine-learning","description":"\u673A\u5668\u5B66\u4E60\u76F8\u5173\u6587\u7AE0"},{"inline":false,"label":"AI","permalink":"/en/blog/tags/ai","description":"\u4EBA\u5DE5\u667A\u80FD\u76F8\u5173\u6587\u7AE0"}],"readingTime":3.95,"hasTruncateMarker":true,"authors":[{"name":"pomili","title":"\u5F00\u53D1\u8005","page":{"permalink":"/en/blog/authors/pomili"},"socials":{"github":"https://github.com/pomili"},"key":"pomili"}],"frontMatter":{"slug":"ml-roadmap","title":"\u673A\u5668\u5B66\u4E60\u5B66\u4E60\u8DEF\u7EBF\uFF1A\u4ECE\u5165\u95E8\u5230\u5B9E\u8DF5","authors":"pomili","tags":["\u673A\u5668\u5B66\u4E60","AI"]},"unlisted":false,"nextItem":{"title":"\u4F7F\u7528 Docusaurus \u642D\u5EFA\u4E2A\u4EBA\u6587\u6863\u7AD9\u70B9","permalink":"/en/blog/hello-docusaurus"}},"content":"\u4ECE\u6570\u5B66\u57FA\u7840\u5230\u5DE5\u7A0B\u843D\u5730\uFF0C\u5206\u4EAB\u4E00\u6761\u53EF\u6267\u884C\u7684\u673A\u5668\u5B66\u4E60\u5B66\u4E60\u8DEF\u7EBF\u3002\\n\\n{/* truncate */}\\n\\n## \u7B2C\u4E00\u9636\u6BB5\uFF1A\u6570\u5B66\u57FA\u7840\\n\\nML \u7684\u6838\u5FC3\u662F\u6570\u5B66\uFF0C\u5EFA\u8BAE\u4F18\u5148\u638C\u63E1\u4EE5\u4E0B\u5185\u5BB9\uFF1A\\n\\n### \u7EBF\u6027\u4EE3\u6570\\n\\n- \u5411\u91CF\u3001\u77E9\u9635\u3001\u5F20\u91CF\u7684\u57FA\u672C\u8FD0\u7B97\\n- \u7279\u5F81\u503C\u548C\u7279\u5F81\u5411\u91CF\uFF08\u7406\u89E3 PCA \u7684\u5173\u952E\uFF09\\n- \u77E9\u9635\u5206\u89E3\uFF08SVD\u3001QR\uFF09\\n\\n\u63A8\u8350\u8D44\u6E90\uFF1A3Blue1Brown \u7684 [\u7EBF\u6027\u4EE3\u6570\u7684\u672C\u8D28](https://www.3blue1brown.com/topics/linear-algebra) \u7CFB\u5217\u89C6\u9891\u3002\\n\\n### \u6982\u7387\u8BBA\u4E0E\u7EDF\u8BA1\\n\\n- \u6982\u7387\u5206\u5E03\uFF08\u9AD8\u65AF\u3001\u4F2F\u52AA\u5229\u3001\u591A\u9879\uFF09\\n- \u8D1D\u53F6\u65AF\u5B9A\u7406\\n- \u6700\u5927\u4F3C\u7136\u4F30\u8BA1\uFF08MLE\uFF09\u548C\u6700\u5927\u540E\u9A8C\u4F30\u8BA1\uFF08MAP\uFF09\\n- \u671F\u671B\u3001\u65B9\u5DEE\u3001\u534F\u65B9\u5DEE\\n\\n### \u5FAE\u79EF\u5206\\n\\n- \u5BFC\u6570\u548C\u504F\u5BFC\u6570\\n- \u94FE\u5F0F\u6CD5\u5219\uFF08\u53CD\u5411\u4F20\u64AD\u7684\u57FA\u7840\uFF09\\n- \u68AF\u5EA6\u4E0B\u964D\u7684\u51E0\u4F55\u7406\u89E3\\n- \u96C5\u53EF\u6BD4\u77E9\u9635\u548C\u6D77\u68EE\u77E9\u9635\uFF08\u4E86\u89E3\u5373\u53EF\uFF09\\n\\n> **\u5EFA\u8BAE**\uFF1A\u4E0D\u8981\u7B49\u6570\u5B66\u5168\u5B66\u5B8C\u518D\u5F00\u59CB\u5199\u4EE3\u7801\uFF0C\u6570\u5B66\u548C\u7F16\u7A0B\u540C\u6B65\u8FDB\u884C\uFF0C\u9047\u5230\u4E0D\u61C2\u7684\u518D\u56DE\u5934\u8865\u3002\\n\\n## \u7B2C\u4E8C\u9636\u6BB5\uFF1A\u7F16\u7A0B\u5DE5\u5177\\n\\n### Python\\n\\nML \u9886\u57DF\u7684\u901A\u7528\u8BED\u8A00\uFF0C\u91CD\u70B9\u638C\u63E1\uFF1A\\n\\n- NumPy \u2014 \u77E9\u9635\u8FD0\u7B97\u548C\u5E7F\u64AD\u673A\u5236\\n- Pandas \u2014 \u6570\u636E\u6E05\u6D17\u548C\u7279\u5F81\u5DE5\u7A0B\\n- Matplotlib / Seaborn \u2014 \u6570\u636E\u53EF\u89C6\u5316\\n- Scikit-learn \u2014 \u7ECF\u5178 ML \u7B97\u6CD5\u7684\u7EDF\u4E00\u63A5\u53E3\\n\\n### \u6DF1\u5EA6\u5B66\u4E60\u6846\u67B6\\n\\n\u4E8C\u9009\u4E00\u5165\u95E8\uFF0C\u540E\u671F\u4E24\u4E2A\u90FD\u8981\u4E86\u89E3\uFF1A\\n\\n- **PyTorch**\uFF08\u63A8\u8350\uFF09\u2014 \u52A8\u6001\u8BA1\u7B97\u56FE\uFF0C\u8C03\u8BD5\u53CB\u597D\uFF0C\u5B66\u672F\u754C\u4E3B\u6D41\\n- **TensorFlow / Keras** \u2014 \u5DE5\u4E1A\u754C\u90E8\u7F72\u6210\u719F\uFF0C\u751F\u6001\u5B8C\u5584\\n\\n## \u7B2C\u4E09\u9636\u6BB5\uFF1A\u7ECF\u5178\u673A\u5668\u5B66\u4E60\\n\\n\u5148\u638C\u63E1\u4F20\u7EDF ML \u518D\u8FDB\u5165\u6DF1\u5EA6\u5B66\u4E60\uFF0C\u5F88\u591A\u601D\u60F3\u662F\u76F8\u901A\u7684\uFF1A\\n\\n### \u76D1\u7763\u5B66\u4E60\\n\\n| \u7B97\u6CD5 | \u6838\u5FC3\u601D\u60F3 | \u9002\u7528\u573A\u666F |\\n|------|---------|---------|\\n| \u7EBF\u6027\u56DE\u5F52 | \u6700\u5C0F\u4E8C\u4E58\u6CD5 | \u8FDE\u7EED\u503C\u9884\u6D4B |\\n| \u903B\u8F91\u56DE\u5F52 | Sigmoid + \u4EA4\u53C9\u71B5 | \u4E8C\u5206\u7C7B\u57FA\u7EBF |\\n| \u51B3\u7B56\u6811 / \u968F\u673A\u68EE\u6797 | \u4FE1\u606F\u589E\u76CA + \u96C6\u6210 | \u8868\u683C\u6570\u636E |\\n| XGBoost / LightGBM | \u68AF\u5EA6\u63D0\u5347\u6811 | Kaggle \u7ADE\u8D5B\u9996\u9009 |\\n| SVM | \u6700\u5927\u95F4\u9694\u5206\u7C7B | \u5C0F\u6837\u672C\u9AD8\u7EF4\u6570\u636E |\\n| KNN | \u8DDD\u79BB\u5EA6\u91CF | \u7B80\u5355\u5206\u7C7B/\u56DE\u5F52 |\\n\\n### \u65E0\u76D1\u7763\u5B66\u4E60\\n\\n- K-Means \u805A\u7C7B\\n- DBSCAN\uFF08\u57FA\u4E8E\u5BC6\u5EA6\u7684\u805A\u7C7B\uFF09\\n- PCA \u964D\u7EF4\\n- t-SNE / UMAP \u53EF\u89C6\u5316\\n\\n### \u6838\u5FC3\u6982\u5FF5\\n\\n- \u504F\u5DEE-\u65B9\u5DEE\u6743\u8861\\n- \u8FC7\u62DF\u5408\u4E0E\u6B63\u5219\u5316\uFF08L1/L2\uFF09\\n- \u4EA4\u53C9\u9A8C\u8BC1\\n- \u7279\u5F81\u5DE5\u7A0B\u4E0E\u7279\u5F81\u9009\u62E9\\n- \u6A21\u578B\u8BC4\u4F30\u6307\u6807\uFF08\u51C6\u786E\u7387\u3001\u7CBE\u786E\u7387\u3001\u53EC\u56DE\u7387\u3001F1\u3001AUC-ROC\uFF09\\n\\n## \u7B2C\u56DB\u9636\u6BB5\uFF1A\u6DF1\u5EA6\u5B66\u4E60\\n\\n### \u57FA\u7840\u7EC4\u4EF6\\n\\n- \u5168\u8FDE\u63A5\u7F51\u7EDC\uFF08MLP\uFF09\\n- \u6FC0\u6D3B\u51FD\u6570\uFF1AReLU\u3001GELU\u3001Sigmoid\u3001Tanh\\n- \u635F\u5931\u51FD\u6570\uFF1A\u4EA4\u53C9\u71B5\u3001MSE\u3001Hinge Loss\\n- \u4F18\u5316\u5668\uFF1ASGD\u3001Adam\u3001AdamW\\n- \u6B63\u5219\u5316\uFF1ADropout\u3001Batch Normalization\u3001Layer Normalization\\n- \u5B66\u4E60\u7387\u8C03\u5EA6\u4E0E\u65E9\u505C\uFF08Early Stopping\uFF09\\n\\n### \u8BA1\u7B97\u673A\u89C6\u89C9\uFF08CV\uFF09\\n\\n- CNN \u57FA\u7840\uFF1A\u5377\u79EF\u3001\u6C60\u5316\u3001\u611F\u53D7\u91CE\\n- \u7ECF\u5178\u67B6\u6784\uFF1ALeNet \u2192 AlexNet \u2192 VGG \u2192 ResNet \u2192 EfficientNet\\n- \u76EE\u6807\u68C0\u6D4B\uFF1AYOLO \u7CFB\u5217\\n- \u56FE\u50CF\u5206\u5272\uFF1AU-Net\\n- \u6570\u636E\u589E\u5F3A\\n\\n### \u81EA\u7136\u8BED\u8A00\u5904\u7406\uFF08NLP\uFF09\\n\\n- \u8BCD\u5411\u91CF\uFF1AWord2Vec\u3001GloVe\\n- RNN / LSTM / GRU\\n- Seq2Seq + Attention\\n- Transformer \u67B6\u6784\uFF08\u5F7B\u5E95\u7406\u89E3\u8FD9\u7BC7\u8BBA\u6587\uFF09\\n- BERT / GPT \u7CFB\u5217\\n- \u5927\u6A21\u578B\u65F6\u4EE3\uFF1APrompt Engineering\u3001RAG\u3001Fine-tuning\\n\\n### \u751F\u6210\u6A21\u578B\\n\\n- GAN\\n- VAE\\n- Diffusion Models\uFF08Stable Diffusion\uFF09\\n- \u81EA\u56DE\u5F52\u6A21\u578B\\n\\n## \u7B2C\u4E94\u9636\u6BB5\uFF1A\u5DE5\u7A0B\u5B9E\u8DF5\\n\\n### \u5FC5\u505A\u9879\u76EE\uFF08\u7531\u6D45\u5165\u6DF1\uFF09\\n\\n1. \u7528 Scikit-learn \u505A\u5B8C\u6574\u7684\u5206\u7C7B/\u56DE\u5F52 pipeline\uFF08\u6570\u636E\u6E05\u6D17 \u2192 \u7279\u5F81\u5DE5\u7A0B \u2192 \u8BAD\u7EC3 \u2192 \u8BC4\u4F30\uFF09\\n2. \u624B\u5199\u6570\u5B57\u8BC6\u522B\uFF08MNIST\uFF09\u2014 CNN \u5165\u95E8\\n3. \u56FE\u50CF\u5206\u7C7B\uFF08CIFAR-10/CIFAR-100\uFF09\u2014 \u5B66\u4E60\u8BAD\u7EC3\u8C03\u53C2\\n4. \u6587\u672C\u5206\u7C7B / \u60C5\u611F\u5206\u6790 \u2014 NLP \u5165\u95E8\\n5. Kaggle \u6BD4\u8D5B\uFF08\u4ECE Tabular Playground \u5F00\u59CB\uFF09\\n6. \u90E8\u7F72\u4E00\u4E2A\u6A21\u578B\u4F5C\u4E3A API \u670D\u52A1\\n\\n### MLOps \u6280\u80FD\\n\\n- \u5B9E\u9A8C\u8FFD\u8E2A\uFF1AMLflow\u3001Weights & Biases\\n- \u6570\u636E\u7248\u672C\u7BA1\u7406\uFF1ADVC\\n- \u6A21\u578B\u90E8\u7F72\uFF1AFastAPI\u3001Docker\\n- \u6A21\u578B\u670D\u52A1\uFF1ATorchServe\u3001Triton Inference Server\\n- \u5DE5\u4F5C\u6D41\u7F16\u6392\uFF1AAirflow\\n\\n## \u5B66\u4E60\u8D44\u6E90\u63A8\u8350\\n\\n### \u8BFE\u7A0B\\n\\n| \u8BFE\u7A0B | \u96BE\u5EA6 | \u7279\u70B9 |\\n|------|------|------|\\n| \u5434\u6069\u8FBE Machine Learning | \u5165\u95E8 | \u7ECF\u5178\u8BFE\u7A0B\uFF0C\u7406\u8BBA\u624E\u5B9E |\\n| \u5434\u6069\u8FBE Deep Learning Specialization | \u5165\u95E8 | \u504F\u4EE3\u7801\uFF0C\u9002\u5408\u5FEB\u901F\u4E0A\u624B |\\n| \u674E\u5B8F\u6BC5 ML \u8BFE\u7A0B | \u5165\u95E8-\u4E2D\u7EA7 | \u4E2D\u6587\u6388\u8BFE\uFF0C\u8BB2\u89E3\u751F\u52A8 |\\n| CS231n (Stanford) | \u4E2D\u7EA7 | \u8BA1\u7B97\u673A\u89C6\u89C9\u65B9\u5411 |\\n| CS224n (Stanford) | \u4E2D\u7EA7 | NLP \u65B9\u5411 |\\n| \u674E\u6C90\u300A\u52A8\u624B\u5B66\u6DF1\u5EA6\u5B66\u4E60\u300B| \u5165\u95E8-\u4E2D\u7EA7 | \u4E2D\u6587\u6559\u6750\uFF0C\u4EE3\u7801\u9A71\u52A8 |\\n\\n### \u4E66\u7C4D\\n\\n- \u300A\u7EDF\u8BA1\u5B66\u4E60\u65B9\u6CD5\u300B\u674E\u822A \u2014 \u7ECF\u5178 ML \u7406\u8BBA\\n- \u300A\u673A\u5668\u5B66\u4E60\u300B\u5468\u5FD7\u534E\uFF08\u897F\u74DC\u4E66\uFF09\u2014 \u5168\u9762\u8986\u76D6\\n- \u300A\u52A8\u624B\u5B66\u6DF1\u5EA6\u5B66\u4E60\u300B(d2l.ai) \u2014 \u4EE3\u7801 + \u7406\u8BBA\uFF0C\u5F3A\u70C8\u63A8\u8350\\n- \u300A\u6DF1\u5EA6\u5B66\u4E60\u300B(\u82B1\u4E66) \u2014 \u9002\u5408\u8FDB\u9636\u67E5\u9605\uFF0C\u4E0D\u9002\u5408\u5165\u95E8\\n\\n### \u5B9E\u8DF5\u5E73\u53F0\\n\\n- **Kaggle** \u2014 \u6BD4\u8D5B + \u6570\u636E\u96C6 + Notebook\\n- **Papers With Code** \u2014 \u8BBA\u6587 + \u590D\u73B0\u4EE3\u7801\\n- **Hugging Face** \u2014 \u6A21\u578B\u548C\u6570\u636E\u96C6\u793E\u533A\\n\\n## \u5B66\u4E60\u5EFA\u8BAE\\n\\n1. **\u4EE3\u7801\u9A71\u52A8**\uFF1A\u770B\u89C6\u9891/\u8BFB\u4E66\u7684\u540C\u65F6\u4E00\u5B9A\u8981\u52A8\u624B\u5199\u4EE3\u7801\uFF0C\u7406\u8BBA\u770B\u61C2\u548C\u80FD\u8DD1\u901A\u662F\u4E24\u56DE\u4E8B\u3002\\n2. **\u505A\u9879\u76EE\u800C\u4E0D\u662F\u5237\u8BFE\u7A0B**\uFF1A\u5B8C\u6210\u4E00\u4E2A\u5B8C\u6574\u9879\u76EE\u6BD4\u4E0A\u5B8C\u5341\u95E8\u8BFE\u66F4\u6709\u4EF7\u503C\u3002\\n3. **\u8BFB\u8BBA\u6587**\uFF1A\u517B\u6210\u8BFB\u8BBA\u6587\u7684\u4E60\u60EF\uFF0C\u4ECE\u7ECF\u5178\u8BBA\u6587\u5F00\u59CB\uFF08ResNet\u3001Transformer\u3001BERT\uFF09\u3002\\n4. **\u5199\u535A\u5BA2\u8BB0\u5F55**\uFF1A\u628A\u5B66\u5230\u7684\u5185\u5BB9\u7528\u81EA\u5DF1\u7684\u8BDD\u5199\u51FA\u6765\uFF0C\u6559\u662F\u6700\u597D\u7684\u5B66\u3002\\n5. **\u4FDD\u6301\u8010\u5FC3**\uFF1AML \u9886\u57DF\u77E5\u8BC6\u66F4\u65B0\u5FEB\uFF0C\u5173\u6CE8\u57FA\u7840\u539F\u7406\u800C\u975E\u8FFD\u9010\u6BCF\u4E2A\u65B0\u70ED\u70B9\u3002\\n\\n---\\n\\n\u5B66\u4E60\u8DEF\u7EBF\u4E0D\u662F\u7EBF\u6027\u7684\uFF0C\u4E0D\u540C\u9636\u6BB5\u4E4B\u95F4\u4F1A\u6709\u4EA4\u53C9\u548C\u5F80\u590D\u3002\u5173\u952E\u662F\u4FDD\u6301\u6301\u7EED\u5B66\u4E60\u7684\u8282\u594F\uFF0C\u6BCF\u5929\u8FDB\u6B65\u4E00\u70B9\u3002"},{"id":"hello-docusaurus","metadata":{"permalink":"/en/blog/hello-docusaurus","editUrl":"https://github.com/pomili/docs-site/tree/main/blog/2026-05-22-hello-docusaurus/index.mdx","source":"@site/blog/2026-05-22-hello-docusaurus/index.mdx","title":"\u4F7F\u7528 Docusaurus \u642D\u5EFA\u4E2A\u4EBA\u6587\u6863\u7AD9\u70B9","description":"\u4ECE\u96F6\u5F00\u59CB\uFF0C\u7528 Docusaurus \u642D\u5EFA\u4E86\u4E00\u4E2A\u4E2A\u4EBA\u6587\u6863\u7AD9\u70B9\u3002","date":"2026-05-22T00:00:00.000Z","tags":[{"inline":false,"label":"Docusaurus","permalink":"/en/blog/tags/docusaurus","description":"Docusaurus \u76F8\u5173\u6587\u7AE0"},{"inline":false,"label":"\u524D\u7AEF","permalink":"/en/blog/tags/frontend","description":"\u524D\u7AEF\u5F00\u53D1\u76F8\u5173\u6587\u7AE0"}],"readingTime":1.01,"hasTruncateMarker":true,"authors":[{"name":"pomili","title":"\u5F00\u53D1\u8005","page":{"permalink":"/en/blog/authors/pomili"},"socials":{"github":"https://github.com/pomili"},"key":"pomili"}],"frontMatter":{"slug":"hello-docusaurus","title":"\u4F7F\u7528 Docusaurus \u642D\u5EFA\u4E2A\u4EBA\u6587\u6863\u7AD9\u70B9","authors":"pomili","tags":["docusaurus","\u524D\u7AEF"]},"unlisted":false,"prevItem":{"title":"\u673A\u5668\u5B66\u4E60\u5B66\u4E60\u8DEF\u7EBF\uFF1A\u4ECE\u5165\u95E8\u5230\u5B9E\u8DF5","permalink":"/en/blog/ml-roadmap"}},"content":"\u4ECE\u96F6\u5F00\u59CB\uFF0C\u7528 Docusaurus \u642D\u5EFA\u4E86\u4E00\u4E2A\u4E2A\u4EBA\u6587\u6863\u7AD9\u70B9\u3002\\n\\n{/* truncate */}\\n\\n## \u4E3A\u4EC0\u4E48\u9009 Docusaurus\\n\\nDocusaurus \u662F Meta \u5F00\u6E90\u7684\u9759\u6001\u7AD9\u70B9\u751F\u6210\u5668\uFF0C\u57FA\u4E8E React \u6784\u5EFA\uFF0C\u4E13\u4E3A\u6280\u672F\u6587\u6863\u8BBE\u8BA1\uFF1A\\n\\n- **MDX \u652F\u6301** \u2014 Markdown + JSX\uFF0C\u6587\u6863\u91CC\u53EF\u4EE5\u5D4C\u5165 React \u7EC4\u4EF6\\n- **\u5F00\u7BB1\u5373\u7528** \u2014 \u641C\u7D22\u3001\u7248\u672C\u7BA1\u7406\u3001i18n\u3001\u6697\u8272\u6A21\u5F0F\u5168\u90E8\u5185\u7F6E\\n- **React \u751F\u6001** \u2014 \u53EF\u4EE5\u81EA\u7531\u6269\u5C55\u81EA\u5B9A\u4E49\u7EC4\u4EF6\\n- **\u9759\u6001\u6784\u5EFA** \u2014 \u7EAF\u9759\u6001\u4EA7\u7269\uFF0C\u90E8\u7F72\u5230\u4EFB\u4F55\u6258\u7BA1\u5E73\u53F0\\n\\n## \u642D\u5EFA\u8FC7\u7A0B\\n\\n\u51E0\u884C\u547D\u4EE4\u5C31\u5B8C\u6210\u4E86\u521D\u59CB\u5316\uFF1A\\n\\n```bash\\nnpx create-docusaurus@latest docs-site classic --typescript\\ncd docs-site\\nnpm start\\n```\\n\\n\u672C\u5730\u5F00\u53D1\u670D\u52A1\u5668\u8DD1\u5728 `http://localhost:3000/`\uFF0C\u4FEE\u6539\u6587\u6863\u5B9E\u65F6\u70ED\u66F4\u65B0\u3002\\n\\n## \u914D\u7F6E\u8981\u70B9\\n\\n\u6838\u5FC3\u914D\u7F6E\u6587\u4EF6\u662F `docusaurus.config.ts`\uFF0C\u51E0\u4E2A\u5173\u952E\u70B9\uFF1A\\n\\n1. **baseUrl** \u2014 \u672C\u5730\u7528 `/`\uFF0C\u90E8\u7F72\u5230 GitHub Pages \u9700\u8981\u6539\u4E3A\u4ED3\u5E93\u540D\uFF0C\u5982 `/docs-site/`\\n2. **i18n** \u2014 \u4E2D\u6587\u7AD9\u70B9\u8BBE\u7F6E `defaultLocale: \'zh-Hans\'`\\n3. **\u4E3B\u9898\u5B9A\u5236** \u2014 \u901A\u8FC7 `custom.css` \u8986\u76D6 Infima \u53D8\u91CF\uFF0C\u5B9E\u73B0\u81EA\u5B9A\u4E49\u914D\u8272\\n\\n## \u90E8\u7F72\\n\\n\u4F7F\u7528 GitHub Actions \u81EA\u52A8\u90E8\u7F72\u5230 GitHub Pages\uFF0C\u63A8\u9001\u5373\u53D1\u5E03\uFF0C\u65E0\u9700\u624B\u52A8\u64CD\u4F5C\u3002\\n\\n---\\n\\n\u8FD9\u53EA\u662F\u5F00\u59CB\u3002\u540E\u9762\u4F1A\u9646\u7EED\u8865\u5145\u66F4\u591A\u5185\u5BB9\uFF0C\u8BB0\u5F55\u5B66\u4E60\u4E0E\u5F00\u53D1\u7684\u8FC7\u7A0B\u3002"}]}}')}}]);